
CREATE TABLE "asistencia_asistencia" ("id" SERIAL PRIMARY KEY, "fecha" date NOT NULL, "hora_entrada" time NULL, "hora_salida" time NULL, "tipo_dia" varchar(20) NOT NULL, "empleado_id" bigint NOT NULL REFERENCES "nucleo_empleado" ("id"), "empresa_id" bigint NOT NULL REFERENCES "core_empresa" ("id"));
CREATE TABLE "asistencia_movimiento" ("id" SERIAL PRIMARY KEY, "tipo" varchar(20) NOT NULL, "asistencia_id" bigint NOT NULL REFERENCES "asistencia_asistencia" ("id"), "fecha" date NOT NULL, "hora" time NOT NULL, creado datetime NOT NULL);
CREATE TABLE "asistencia_tiempoextra" ("id" SERIAL PRIMARY KEY, "fecha" date NOT NULL, "hora_inicio" time NOT NULL, "asistencia_id" bigint NOT NULL REFERENCES "asistencia_asistencia" ("id"), "empleado_id" bigint NOT NULL REFERENCES "nucleo_empleado" ("id"), "horas" real NULL, "hora_fin" time NULL);
CREATE TABLE "auth_group" ("id" SERIAL PRIMARY KEY, "name" varchar(150) NOT NULL UNIQUE);
CREATE TABLE "auth_group_permissions" ("id" SERIAL PRIMARY KEY, "group_id" integer NOT NULL REFERENCES "auth_group" ("id"), "permission_id" integer NOT NULL REFERENCES "auth_permission" ("id"),
CREATE TABLE "auth_permission" ("id" SERIAL PRIMARY KEY, "content_type_id" integer NOT NULL REFERENCES "django_content_type" ("id"), "codename" varchar(100) NOT NULL, "name" varchar(255) NOT NULL);
CREATE TABLE "auth_user" ("id" SERIAL PRIMARY KEY, "password" varchar(128) NOT NULL, "last_login" datetime NULL, "is_superuser" bool NOT NULL, "username" varchar(150) NOT NULL UNIQUE, "last_name" varchar(150) NOT NULL, "email" varchar(254) NOT NULL, "is_staff" bool NOT NULL, "is_active" bool NOT NULL, "date_joined" datetime NOT NULL, "first_name" varchar(150) NOT NULL);
CREATE TABLE "auth_user_groups" ("id" SERIAL PRIMARY KEY, "user_id" integer NOT NULL REFERENCES "auth_user" ("id"), "group_id" integer NOT NULL REFERENCES "auth_group" ("id"),
CREATE TABLE "auth_user_user_permissions" ("id" SERIAL PRIMARY KEY, "user_id" integer NOT NULL REFERENCES "auth_user" ("id"),
CREATE TABLE "checador_checada" ("id" SERIAL PRIMARY KEY, "empleado" varchar(150) NOT NULL, "fecha" date NOT NULL, "entrada" time NULL, "salida" time NULL);
CREATE TABLE "core_empresa" ("id" SERIAL PRIMARY KEY, "nombre" varchar(150) NOT NULL, varchar(50) NOT NULL UNIQUE, "activa" bool NOT NULL);
CREATE TABLE "core_empresausuario" ("id" SERIAL PRIMARY KEY, "empresa_id" bigint NOT NULL REFERENCES "core_empresa" ("id"),  "usuario_id" integer NOT NULL REFERENCES "auth_user" ("id"), 
CREATE TABLE "core_incidencia" ("id" SERIAL PRIMARY KEY, "tipo" varchar(30) NOT NULL, "fecha_inicio" date NOT NULL, "fecha_fin" date NOT NULL, "empleado_id" bigint NOT NULL REFERENCES "nucleo_empleado" ("id"), "turno_id" bigint NULL REFERENCES "core_turno" ("id"), 
CREATE TABLE "core_incidenciadia" ("id" SERIAL PRIMARY KEY, "fecha" date NOT NULL, "tipo" varchar(30) NOT NULL, "empleado_id" bigint NOT NULL REFERENCES "nucleo_empleado" ("id"), "incidencia_id" bigint NOT NULL REFERENCES "core_incidencia" ("id"),
CREATE TABLE "core_perfil" ("id" SERIAL PRIMARY KEY, "empresa_id" bigint NULL REFERENCES "core_empresa" ("id"), "user_id" integer NOT NULL UNIQUE REFERENCES "auth_user" ("id"), 
CREATE TABLE "core_turno" ("id" SERIAL PRIMARY KEY, "nombre" varchar(100) NOT NULL, "hora_entrada" time NOT NULL, "hora_salida" time NOT NULL, "tolerancia_minutos" integer NOT NULL, "activo" bool NOT NULL, "empresa_id" bigint NOT NULL REFERENCES "core_empresa" ("id"),  
CREATE TABLE "django_admin_log" ("id" SERIAL PRIMARY KEY, "object_id" text NULL, "object_repr" varchar(200) NOT NULL, "action_flag" smallint unsigned NOT NULL CHECK ("action_flag" >= 0), "change_message" text NOT NULL, "content_type_id" integer NULL REFERENCES "django_content_type" ("id"), "user_id" integer NOT NULL REFERENCES "auth_user" ("id"), "action_time" datetime NOT NULL);
CREATE TABLE "django_content_type" ("id" SERIAL PRIMARY KEY, "app_label" varchar(100) NOT NULL, "model" varchar(100) NOT NULL);
CREATE TABLE "django_migrations" ("id" SERIAL PRIMARY KEY, "app" varchar(255) NOT NULL, "name" varchar(255) NOT NULL, "applied" datetime NOT NULL);
CREATE TABLE "django_session" ("session_key" varchar(40) NOT NULL PRIMARY KEY, "session_data" text NOT NULL, "expire_date" datetime NOT NULL);
CREATE TABLE "nucleo_departamento" ("id" SERIAL PRIMARY KEY, "nombre" varchar(100) NOT NULL, "empresa_id" bigint NOT NULL REFERENCES "core_empresa" ("id"), "activo" bool NOT NULL, "trabaja_fines_semana" bool NOT NULL);
CREATE TABLE "nucleo_empleado" ("id" SERIAL PRIMARY KEY, "nombre" varchar(100) NOT NULL, "numero_empleado" varchar(10) NOT NULL, "activo" bool NOT NULL, "empresa_id" bigint NOT NULL REFERENCES "core_empresa" ("id"),
CREATE TABLE "saas_empresa" ("id" SERIAL PRIMARY KEY, "nombre" varchar(150) NOT NULL, "activa" bool NOT NULL, creado datetime NOT NULL);
CREATE TABLE "saas_perfil" ("id" SERIAL PRIMARY KEY, "empresa_id" bigint NOT NULL REFERENCES "saas_empresa" ("id"), "user_id" integer NOT NULL UNIQUE REFERENCES "auth_user" ("id"),
